rows.customCode:
(() => {
  // pcbw: UI-Heavy Interactive Builder Bot - iframe floating panel with checklist workflow
  if (window.__pcbw_uiBuilderInit) return;
  window.__pcbw_uiBuilderInit = true;

  oc.thread.customData ||= {};
  if (!oc.thread.customData.__pcbw_checklist) {
    oc.thread.customData.__pcbw_checklist = [];
  }
  if (typeof oc.thread.customData.__pcbw_panelOpen !== "boolean") {
    oc.thread.customData.__pcbw_panelOpen = false;
  }

  var panelId = "__pcbw_builder_panel";
  var toggleBtnId = "__pcbw_builder_toggle";

  function getChecklist() {
    oc.thread.customData ||= {};
    if (!Array.isArray(oc.thread.customData.__pcbw_checklist)) {
      oc.thread.customData.__pcbw_checklist = [];
    }
    return oc.thread.customData.__pcbw_checklist;
  }

  function renderPanel() {
    var panel = document.getElementById(panelId);
    if (!panel) return;
    var items = getChecklist();
    var html = '<div style="padding:12px;font-family:system-ui,sans-serif;font-size:14px;">';
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">';
    html += '<strong style="color:light-dark(#1a1a2e,#e0e0ff);">Project Checklist</strong>';
    html += '<button id="__pcbw_close_panel" style="background:none;border:none;font-size:18px;cursor:pointer;color:light-dark(#666,#aaa);">x</button>';
    html += '</div>';

    if (items.length === 0) {
      html += '<p style="color:light-dark(#888,#999);font-style:italic;">No items yet. Tell the bot what you want to build!</p>';
    } else {
      html += '<div style="max-height:250px;overflow-y:auto;">';
      for (var i = 0; i < items.length; i++) {
        var item = items[i];
        var checked = item.done ? "checked" : "";
        var textStyle = item.done ? "text-decoration:line-through;color:light-dark(#999,#666);" : "color:light-dark(#333,#ddd);";
        html += '<label style="display:flex;align-items:flex-start;gap:8px;padding:4px 0;cursor:pointer;">';
        html += '<input type="checkbox" data-idx="' + i + '" ' + checked + ' style="margin-top:3px;cursor:pointer;">';
        html += '<span style="' + textStyle + '">' + escapeHtml(item.text) + '</span>';
        html += '</label>';
      }
      html += '</div>';
    }

    var doneCount = items.filter(function(x) { return x.done; }).length;
    if (items.length > 0) {
      var pct = Math.round((doneCount / items.length) * 100);
      html += '<div style="margin-top:10px;background:light-dark(#e0e0e0,#333);border-radius:4px;overflow:hidden;height:8px;">';
      html += '<div style="width:' + pct + '%;height:100%;background:light-dark(#4caf50,#66bb6a);transition:width 0.3s;"></div>';
      html += '</div>';
      html += '<div style="text-align:right;margin-top:4px;font-size:12px;color:light-dark(#666,#aaa);">' + doneCount + '/' + items.length + ' complete</div>';
    }

    html += '<div style="margin-top:10px;display:flex;gap:6px;">';
    html += '<input id="__pcbw_new_item" type="text" placeholder="Add item..." style="flex:1;padding:6px 8px;border:1px solid light-dark(#ccc,#555);border-radius:4px;background:light-dark(#fff,#222);color:light-dark(#333,#ddd);font-size:13px;">';
    html += '<button id="__pcbw_add_item" style="padding:6px 12px;background:light-dark(#4a90d9,#5a9ae6);color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:13px;">Add</button>';
    html += '</div>';
    html += '</div>';

    panel.innerHTML = html;
    attachPanelEvents();
  }

  function escapeHtml(str) {
    return String(str).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
  }

  function attachPanelEvents() {
    var closeBtn = document.getElementById("__pcbw_close_panel");
    if (closeBtn) {
      closeBtn.onclick = function() { togglePanel(false); };
    }

    var addBtn = document.getElementById("__pcbw_add_item");
    var input = document.getElementById("__pcbw_new_item");
    if (addBtn && input) {
      addBtn.onclick = function() {
        var val = input.value.trim();
        if (val) {
          getChecklist().push({ text: val, done: false });
          renderPanel();
        }
      };
      input.onkeydown = function(e) {
        if (e.key === "Enter") { addBtn.click(); }
      };
    }

    var checkboxes = document.querySelectorAll("#" + panelId + " input[type=checkbox]");
    for (var c = 0; c < checkboxes.length; c++) {
      checkboxes[c].onchange = (function(idx) {
        return function(e) {
          var list = getChecklist();
          if (list[idx]) {
            list[idx].done = e.target.checked;
            renderPanel();
          }
        };
      })(parseInt(checkboxes[c].getAttribute("data-idx"), 10));
    }
  }

  function togglePanel(forceState) {
    var panel = document.getElementById(panelId);
    var isOpen = typeof forceState === "boolean" ? forceState : !panel || panel.style.display === "none";
    oc.thread.customData.__pcbw_panelOpen = isOpen;

    if (!panel) {
      panel = document.createElement("div");
      panel.id = panelId;
      panel.style.cssText = "position:fixed;top:80px;right:16px;width:320px;max-height:450px;overflow-y:auto;z-index:99999;border-radius:8px;box-shadow:0 4px 20px rgba(0,0,0,0.25);background:light-dark(#ffffff,#1a1a2e);border:1px solid light-dark(#ddd,#333);";
      document.body.appendChild(panel);
    }

    panel.style.display = isOpen ? "block" : "none";
    if (isOpen) { renderPanel(); }
  }

  // Create toggle button
  if (!document.getElementById(toggleBtnId)) {
    var btn = document.createElement("button");
    btn.id = toggleBtnId;
    btn.textContent = "Checklist";
    btn.style.cssText = "position:fixed;top:16px;right:16px;z-index:100000;padding:8px 16px;background:light-dark(#4a90d9,#5a9ae6);color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:14px;font-family:system-ui,sans-serif;box-shadow:0 2px 8px rgba(0,0,0,0.2);";
    btn.onclick = function() { togglePanel(); };
    document.body.appendChild(btn);
  }

  // Slash commands for checklist management
  oc.thread.on("MessageAdded", function(msg) {
    if (msg.author !== "user") return;
    var text = (msg.content || "").trim();

    if (text === "/checklist") {
      togglePanel(true);
      oc.thread.messages.push({
        author: "system",
        content: "Checklist panel opened.",
        hiddenFrom: ["ai"],
        expectsReply: false
      });
      return;
    }

    if (text.startsWith("/add ")) {
      var item = text.slice(5).trim();
      if (item) {
        getChecklist().push({ text: item, done: false });
        renderPanel();
        oc.thread.messages.push({
          author: "system",
          content: "Added to checklist: " + item,
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      }
      return;
    }

    if (text === "/progress") {
      var items = getChecklist();
      var done = items.filter(function(x) { return x.done; }).length;
      var total = items.length;
      var summary = total === 0 ? "No checklist items yet." : done + "/" + total + " items complete (" + Math.round((done/total)*100) + "%)";
      oc.thread.messages.push({
        author: "system",
        content: summary,
        hiddenFrom: [],
        expectsReply: false
      });
      return;
    }
  });
})();
